import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import products from "../data/ProductData"; // fallback data
import "../index.css";

const Checkout = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [formData, setFormData] = useState({
    name: "",
    mobile: "",
    address: "",
    promoCode: "",
    modeOfPayment: "",
  });
  const [orderPlaced, setOrderPlaced] = useState(false);

  useEffect(() => {
    if (!id) return;

    const dummy = products.find((p) => String(p.id) === id);
    if (dummy) {
      setProduct(dummy);
      return;
    }

    axios
      .get('http://localhost:5000/api/products/${id}')
      .then((res) => {
        if (res.data) setProduct(res.data);
        else setProduct({ name: "Unknown Product", price: 0, _id: id });
      })
      .catch((err) => {
        console.error("Error loading product:", err);
        setProduct({ name: "Unknown Product", price: 0, _id: id });
      });
  }, [id]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setOrderPlaced(true);
    console.log("Order placed:", { product, ...formData });

    setTimeout(() => navigate("/orders"), 2000);
  };

  if (!product) return <p>Loading product...</p>;
  if (orderPlaced) return <h2 className="success-msg">✅ Order placed successfully!</h2>;

  return (
    <div className="checkout-container">
      <h2>Checkout</h2>

      <div className="checkout-details">
        <p><strong>Product:</strong> {product.name}</p>
        <p><strong>Price:</strong> ₹{product.price}</p>
      </div>

      <form onSubmit={handleSubmit} className="checkout-form">
        <label>Full Name</label>
        <input
          type="text"
          name="name"
          value={formData.name}
          onChange={handleChange}
          required
          placeholder="Enter your name"
        />

        <label>Mobile Number</label>
        <input
          type="tel"
          name="mobile"
          value={formData.mobile}
          onChange={handleChange}
          required
          placeholder="Enter your mobile number"
        />

        <label>Address</label>
        <textarea
          name="address"
          value={formData.address}
          onChange={handleChange}
          required
          placeholder="Enter full address"
        />

        <label>Promo Code</label>
        <input
          type="text"
          name="promoCode"
          value={formData.promoCode}
          onChange={handleChange}
          placeholder="Optional"
        />

        <label>Mode of Payment</label>
        <select
          name="modeOfPayment"
          value={formData.modeOfPayment}
          onChange={handleChange}
          required
        >
          <option value="">Select Payment Mode</option>
          <option value="UPI">UPI</option>
          <option value="Credit Card">Credit Card</option>
          <option value="Debit Card">Debit Card</option>
          <option value="Cash on Delivery">Cash on Delivery</option>
        </select>

        <button type="submit" className="place-order-btn">
          Place Order
        </button>
      </form>
    </div>
  );
};

export default Checkout;
